def count_unique(nums):
    if not nums:  # Edge case handling for an empty list
        return 0
    count_dict = {}
    for num in nums:
        if num in count_dict:
            count_dict[num] += 1
        else:
            count_dict[num] = 1
    return sum(1 for value in count_dict.values() if value == 1)
